# Database setup
Base = declarative_base()

# Association table for many-to-many relationship between products and categories
product_categories = Table(
    'product_categories',
    Base.metadata,
    Column('product_id', Integer, ForeignKey('products.id'), primary_key=True),
    Column('category_id', Integer, ForeignKey('categories.id'), primary_key=True),
)


# SQLAlchemy Models
class ProductModel(Base):
    __tablename__ = 'products'

    id = Column(Integer, primary_key=True, autoincrement=True)
    name = Column(String(255), nullable=False)
    description = Column(Text, nullable=True)
    price = Column(Float, nullable=False)
    seller_id = Column(Integer, ForeignKey('sellers.id'), nullable=True)

    seller = relationship('SellerModel', back_populates='products')
    reviews = relationship('ReviewModel', back_populates='product', cascade='all, delete-orphan')
    categories = relationship('CategoryModel', secondary=product_categories, back_populates='products')
    images = relationship('ImageModel', back_populates='product', cascade='all, delete-orphan')


class SellerModel(Base):
    __tablename__ = 'sellers'

    id = Column(Integer, primary_key=True, autoincrement=True)
    name = Column(String(255), nullable=False)
    email = Column(String(255), nullable=True)
    rating = Column(Float, nullable=True)

    products = relationship('ProductModel', back_populates='seller')


class ReviewModel(Base):
    __tablename__ = 'reviews'

    id = Column(Integer, primary_key=True, autoincrement=True)
    product_id = Column(Integer, ForeignKey('products.id'), nullable=False)
    author = Column(String(255), nullable=False)
    content = Column(Text, nullable=True)
    rating = Column(Integer, nullable=False)

    product = relationship('ProductModel', back_populates='reviews')


class CategoryModel(Base):
    __tablename__ = 'categories'

    id = Column(Integer, primary_key=True, autoincrement=True)
    name = Column(String(255), nullable=False)
    description = Column(Text, nullable=True)
    parent_id = Column(Integer, ForeignKey('categories.id'), nullable=True)

    parent = relationship('CategoryModel', remote_side=[id], back_populates='children')
    children = relationship('CategoryModel', back_populates='parent')
    products = relationship('ProductModel', secondary=product_categories, back_populates='categories')


class ImageModel(Base):
    __tablename__ = 'images'

    id = Column(Integer, primary_key=True, autoincrement=True)
    product_id = Column(Integer, ForeignKey('products.id'), nullable=False)
    url = Column(String(500), nullable=False)
    alt_text = Column(String(255), nullable=True)
    is_primary = Column(Integer, default=0)  # 0 = False, 1 = True (SQLite compatible)

    product = relationship('ProductModel', back_populates='images')


# Database engine and session
DATABASE_URL = "sqlite:///./products.db"
engine = create_engine(DATABASE_URL, echo=False)
SessionLocal = sessionmaker(bind=engine)


@contextmanager
def get_session():
    session = SessionLocal()
    try:
        yield session
    finally:
        session.close()


# Strawberry GraphQL Types
@strawberry.type
class Image:
    id: int
    url: str
    alt_text: Optional[str]
    is_primary: bool


@strawberry.type
class Review:
    id: int
    author: str
    content: Optional[str]
    rating: int


@strawberry.type
class Category:
    id: int
    name: str
    description: Optional[str]

    @strawberry.field
    def parent(self, info: Info) -> Optional["Category"]:
        with get_session() as session:
            cat = session.query(CategoryModel).filter(CategoryModel.id == self.id).first()
            if cat and cat.parent_id:
                parent = session.query(CategoryModel).filter(CategoryModel.id == cat.parent_id).first()
                if parent:
                    return Category(
                        id=parent.id,
                        name=parent.name,
                        description=parent.description,
                    )
        return None

    @strawberry.field
    def children(self, info: Info) -> List["Category"]:
        with get_session() as session:
            children = session.query(CategoryModel).filter(CategoryModel.parent_id == self.id).all()
            return [
                Category(id=c.id, name=c.name, description=c.description)
                for c in children
            ]

    @strawberry.field
    def products(self, info: Info) -> List["Product"]:
        with get_session() as session:
            cat = session.query(CategoryModel).options(
                joinedload(CategoryModel.products)
                .joinedload(ProductModel.seller),
                joinedload(CategoryModel.products)
                .joinedload(ProductModel.reviews),
                joinedload(CategoryModel.products)
                .joinedload(ProductModel.images),
                joinedload(CategoryModel.products)
                .joinedload(ProductModel.categories),
            ).filter(CategoryModel.id == self.id).first()
            if cat:
                return [_product_model_to_type(p) for p in cat.products]
        return []


@strawberry.type
class Seller:
    id: int
