@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_product(self, info: Info, input: CreateProductInput) -> Product:
        with get_session() as session:
            product = ProductModel(
                name=input.name,
                description=input.description,
                price=input.price,
                seller_id=input.seller_id,
            )

            if input.category_ids:
                categories = session.query(CategoryModel).filter(
                    CategoryModel.id.in_(input.category_ids)
                ).all()
                product.categories = categories

            session.add(product)
            session.commit()
            session.refresh(product)

            # Reload with relationships
            p = session.query(ProductModel).options(
                joinedload(ProductModel.seller),
                joinedload(ProductModel.reviews),
                joinedload(ProductModel.categories),
                joinedload(ProductModel.images),
            ).filter(ProductModel.id == product.id).first()

            return _product_model_to_type(p)

    @strawberry.mutation
    def create_review(self, info: Info, input: CreateReviewInput) -> Review:
        with get_session() as session:
            review = ReviewModel(
                product_id=input.product_id,
                author=input.author,
                content=input.content,
                rating=input.rating,
            )
            session.add(review)
            session.commit()
            session.refresh(review)
            return Review(
                id=review.id,
                author=review.author,
                content=review.content,
                rating=review.rating,
            )

    @strawberry.mutation
    def create_seller(self, info: Info, input: CreateSellerInput) -> Seller:
        with get_session() as session:
            seller = SellerModel(
                name=input.name,
                email=input.email,
                rating=input.rating,
            )
            session.add(seller)
            session.commit()
            session.refresh(seller)
            return Seller(
                id=seller.id,
                name=seller.name,
                email=seller.email,
                rating=seller.rating,
            )

    @strawberry.mutation
    def create_category(self, info: Info, input: CreateCategoryInput) -> Category:
        with get_session() as session:
            category = CategoryModel(
                name=input.name,
                description=input.description,
                parent_id=input.parent_id,
            )
            session.add(category)
            session.commit()
            session.refresh(category)
            return Category(
                id=category.id,
                name=category.name,
                description=category.description,
            )

    @strawberry.mutation
    def add_image(self, info: Info, input: AddImageInput) -> Image:
        with get_session() as session:
            image = ImageModel(
                product_id=input.product_id,
                url=input.url,
                alt_text=input.alt_text,
                is_primary=1 if input.is_primary else 0,
            )
            session.add(image)
            session.commit()
            session.refresh(image)
            return Image(
                id=image.id,
                url=image.url,
                alt_text=image.alt_text,
                is_primary=bool(image.is_primary),
            )

    @strawberry.mutation
    def delete_product(self, info: Info, id: int) -> bool:
        with get_session() as session:
            product = session.query(ProductModel).filter(ProductModel.id == id).first()
            if product is None:
                return False
            session.delete(product)
            session.commit()
            return True


